196	func TestRouteStatus_RouteAttemptCooldownSurfaces(t *testing.T) {
197		svc := routeAttemptTestService(t, 30*time.Second)
198		recordedAt := time.Now().Add(-time.Second).UTC()
199		if err := svc.RecordRouteAttempt(context.Background(), RouteAttempt{
200			Harness:   "fiz",
201			Provider:  "bragi",
202			Model:     "qwen",
203			Status:    "failed",
204			Reason:    "rate_limit",
205			Error:     "429 too many requests",
206			Timestamp: recordedAt,
207		}); err != nil {
208			t.Fatalf("RecordRouteAttempt: %v", err)
209		}
210	
211		report, err := svc.RouteStatus(context.Background())
212		if err != nil {
213			t.Fatalf("RouteStatus: %v", err)
214		}
215		if len(report.Routes) != 1 {
216			t.Fatalf("Routes: got %d, want 1", len(report.Routes))
217		}
218		byProvider := make(map[string]RouteCandidateStatus)
219		for _, cand := range report.Routes[0].Candidates {
220			byProvider[cand.Provider] = cand
221		}
222		bragi := byProvider["bragi"]
223		if bragi.Healthy {
224			t.Fatal("bragi should be unhealthy while route-attempt cooldown is active")
225		}
226		if bragi.Cooldown == nil {
227			t.Fatal("bragi cooldown should be populated")
228		}
229		if bragi.Cooldown.Reason != "rate_limit" {
230			t.Fatalf("Cooldown.Reason: got %q, want rate_limit", bragi.Cooldown.Reason)
231		}
232		if bragi.Cooldown.LastError != "429 too many requests" {
233			t.Fatalf("Cooldown.LastError: got %q", bragi.Cooldown.LastError)
234		}
235		if !bragi.Cooldown.LastAttempt.Equal(recordedAt) {
236			t.Fatalf("Cooldown.LastAttempt: got %s, want %s", bragi.Cooldown.LastAttempt, recordedAt)
237		}
238		if !byProvider["openrouter"].Healthy {
239			t.Fatal("openrouter should remain healthy")
240		}
241	}
