243	func TestRouteAttempts_ProviderModelKeying(t *testing.T) {
244		svc := newTestService(t, ServiceOptions{})
245		ctx := context.Background()
246	
247		keyX := routing.ProviderModelKey("providerA", "", "modelX")
248		keyY := routing.ProviderModelKey("providerA", "", "modelY")
249	
250		for i := 0; i < 3; i++ {
251			if err := svc.RecordRouteAttempt(ctx, RouteAttempt{
252				Harness:  "fiz",
253				Provider: "providerA",
254				Model:    "modelX",
255				Status:   "failed",
256				Error:    "boom",
257				Duration: 100 * time.Millisecond,
258			}); err != nil {
259				t.Fatalf("RecordRouteAttempt failure %d on modelX: %v", i, err)
260			}
261		}
262	
263		successRate, latencyMS := svc.routeMetricSignals(time.Now(), 30*time.Second)
264		if got, want := successRate[keyX], 0.0; got != want {
265			t.Fatalf("after 3 failures on modelX: successRate[%s]=%v, want %v", keyX, got, want)
266		}
267		if _, ok := successRate[keyY]; ok {
268			t.Fatalf("modelY signal should be untouched by modelX failures, got successRate[%s]=%v", keyY, successRate[keyY])
269		}
270		if _, ok := latencyMS[keyY]; ok {
271			t.Fatalf("modelY latency should be untouched by modelX failures, got latencyMS[%s]=%v", keyY, latencyMS[keyY])
272		}
273	
274		if err := svc.RecordRouteAttempt(ctx, RouteAttempt{
275			Harness:  "fiz",
276			Provider: "providerA",
277			Model:    "modelY",
278			Status:   "success",
279			Duration: 50 * time.Millisecond,
280		}); err != nil {
281			t.Fatalf("RecordRouteAttempt success on modelY: %v", err)
282		}
283	
284		successRate, _ = svc.routeMetricSignals(time.Now(), 30*time.Second)
285		if got, want := successRate[keyX], 0.0; got != want {
286			t.Fatalf("after success on modelY: successRate[%s]=%v, want %v (cross-pollution)", keyX, got, want)
287		}
288		if got, want := successRate[keyY], 1.0; got != want {
289			t.Fatalf("after success on modelY: successRate[%s]=%v, want %v", keyY, got, want)
290		}
291	}
