355	func TestBuildRoutingInputs_GeminiQuotaGatesAutoRouting(t *testing.T) {
356		dir := t.TempDir()
357		quotaPath := filepath.Join(dir, "gemini-quota.json")
358		t.Setenv("FIZEAU_GEMINI_QUOTA_CACHE", quotaPath)
359		t.Setenv("FIZEAU_CODEX_QUOTA_CACHE", filepath.Join(dir, "missing-codex-quota.json"))
360		t.Setenv("FIZEAU_CLAUDE_QUOTA_CACHE", filepath.Join(dir, "missing-claude-quota.json"))
361	
362		registry := harnesses.NewRegistry()
363		svc := &service{opts: ServiceOptions{}, registry: registry}
364	
365		// Missing cache: no SubscriptionOK even with fresh auth.
366		t.Setenv("GOOGLE_API_KEY", "test")
367		gemini := routingHarnessEntry(t, svc.buildRoutingInputs(context.Background()).Harnesses, "gemini")
368		if gemini.SubscriptionOK || gemini.QuotaOK {
369			t.Fatalf("missing gemini quota cache must keep gemini out of auto-routing: %+v", gemini)
370		}
371	
372		// Stale snapshot: ineligible even though windows show headroom.
373		if err := geminiharness.WriteGeminiQuota(quotaPath, geminiharness.GeminiQuotaSnapshot{
374			CapturedAt: time.Now().UTC().Add(-1 * time.Hour),
375			Source:     "pty",
376			Windows: []harnesses.QuotaWindow{
377				{Name: "Flash", LimitID: "gemini-flash", UsedPercent: 4, State: "ok"},
378			},
379		}); err != nil {
380			t.Fatalf("WriteGeminiQuota stale: %v", err)
381		}
382		gemini = routingHarnessEntry(t, svc.buildRoutingInputs(context.Background()).Harnesses, "gemini")
383		if gemini.SubscriptionOK || !gemini.QuotaStale {
384			t.Fatalf("stale gemini quota: SubscriptionOK=%v QuotaStale=%v", gemini.SubscriptionOK, gemini.QuotaStale)
385		}
386	
387		// Fresh but all tiers exhausted: routing must still mark ineligible.
388		if err := geminiharness.WriteGeminiQuota(quotaPath, geminiharness.GeminiQuotaSnapshot{
389			CapturedAt: time.Now().UTC(),
390			Source:     "pty",
391			Windows: []harnesses.QuotaWindow{
392				{Name: "Flash", LimitID: "gemini-flash", UsedPercent: 100, State: "exhausted"},
393				{Name: "Pro", LimitID: "gemini-pro", UsedPercent: 100, State: "exhausted"},
394			},
395		}); err != nil {
396			t.Fatalf("WriteGeminiQuota exhausted: %v", err)
397		}
398		gemini = routingHarnessEntry(t, svc.buildRoutingInputs(context.Background()).Harnesses, "gemini")
399		if gemini.SubscriptionOK {
400			t.Fatalf("all tiers exhausted must block gemini auto-routing: %+v", gemini)
401		}
402		if gemini.QuotaTrend != routing.QuotaTrendExhausting {
403			t.Fatalf("all-exhausted snapshot should report exhausting trend, got %q", gemini.QuotaTrend)
404		}
405	
406		// Fresh with at least one non-exhausted tier: routing marks eligible.
407		if err := geminiharness.WriteGeminiQuota(quotaPath, geminiharness.GeminiQuotaSnapshot{
408			CapturedAt: time.Now().UTC(),
409			Source:     "pty",
410			Windows: []harnesses.QuotaWindow{
411				{Name: "Flash", LimitID: "gemini-flash", UsedPercent: 4, State: "ok"},
412				{Name: "Pro", LimitID: "gemini-pro", UsedPercent: 100, State: "exhausted"},
413			},
414		}); err != nil {
415			t.Fatalf("WriteGeminiQuota ok: %v", err)
416		}
417		gemini = routingHarnessEntry(t, svc.buildRoutingInputs(context.Background()).Harnesses, "gemini")
418		if !gemini.SubscriptionOK || !gemini.QuotaOK {
419			t.Fatalf("fresh gemini quota with headroom should mark gemini SubscriptionOK/QuotaOK: %+v", gemini)
420		}
421	}
