1	package gemini
2	
3	import (
4		"encoding/json"
5		"os"
6		"path/filepath"
7		"strings"
8		"time"
9	
10		"github.com/easel/fizeau/internal/harnesses"
11		"github.com/easel/fizeau/internal/safefs"
12	)
13	
14	const geminiAuthFreshnessWindow = 7 * 24 * time.Hour
15	
16	const (
17		authTypeGeminiAPIKey = "gemini-api-key"
18		authTypeOAuth        = "oauth-personal"
19		authTypeVertexAI     = "vertex-ai"
20		authTypeComputeADC   = "compute-default-credentials"
21		authTypeGateway      = "gateway"
22	)
23	
24	// authSnapshot captures non-secret Gemini CLI auth/account evidence. It never
25	// stores API keys, OAuth tokens, refresh tokens, or raw credential payloads.
26	type authSnapshot struct {
27		Authenticated bool
28		AuthType      string
29		Account       *harnesses.AccountInfo
30		CapturedAt    time.Time
31		Fresh         bool
32		Source        string
33		Detail        string
34	}
35	
36	// readAuthEvidence reads Gemini CLI auth evidence from the user's configured
37	// environment and ~/.gemini directory. It is best-effort because Gemini CLI has
38	// no stable non-interactive quota command; routing uses this as auth/account
39	// freshness evidence and exposes quota as unknown.
40	func readAuthEvidence(now time.Time) authSnapshot {
41		if now.IsZero() {
42			now = time.Now()
43		}
44		if authType := authTypeFromEnv(); authType != "" {
45			return authSnapshot{
46				Authenticated: true,
47				AuthType:      authType,
48				Account:       accountForAuthType(authType),
49				CapturedAt:    now.UTC(),
50				Fresh:         true,
51				Source:        "environment",
52				Detail:        "Gemini auth selected from environment; secret values are not read",
53			}
54		}
55		home, err := os.UserHomeDir()
56		if err != nil || home == "" {
57			return authSnapshot{Source: "~/.gemini", Detail: "home directory unavailable"}
58		}
59		return readAuthEvidenceFromDir(filepath.Join(home, ".gemini"), now)
60	}
61	
62	// readAuthEvidenceFromDir reads non-secret Gemini CLI auth evidence from a
63	// caller-provided .gemini directory. Tests use this for credential-free replay.
64	func readAuthEvidenceFromDir(dir string, now time.Time) authSnapshot {
65		if now.IsZero() {
66			now = time.Now()
67		}
68		settingsPath := filepath.Join(dir, "settings.json")
69		authType, settingsTime, settingsOK := readSelectedAuthType(settingsPath)
70		if authType == "" {
71			return authSnapshot{
72				Source:     settingsPath,
73				CapturedAt: settingsTime,
74				Fresh:      settingsOK && isFresh(settingsTime, now),
75				Detail:     "Gemini CLI auth method not configured",
76			}
77		}
78	
79		switch authType {
80		case authTypeOAuth:
81			return readOAuthEvidence(dir, authType, settingsTime, now)
82		case authTypeGeminiAPIKey, authTypeVertexAI, authTypeGateway, authTypeComputeADC:
83			return authSnapshot{
84				Authenticated: true,
85				AuthType:      authType,
86				Account:       accountForAuthType(authType),
87				CapturedAt:    settingsTime,
88				Fresh:         isFresh(settingsTime, now),
89				Source:        settingsPath,
90				Detail:        "Gemini CLI auth method configured; secret material is external to DDx",
91			}
92		default:
93			return authSnapshot{
94				AuthType:   authType,
95				Source:     settingsPath,
96				CapturedAt: settingsTime,
97				Fresh:      isFresh(settingsTime, now),
98				Detail:     "Gemini CLI auth method is not recognized by DDx",
99			}
100		}
101	}
102	
103	func readSelectedAuthType(path string) (string, time.Time, bool) {
104		st, err := os.Stat(path)
105		if err != nil || st.IsDir() {
106			return "", time.Time{}, false
107		}
108		data, err := safefs.ReadFile(path)
109		if err != nil {
110			return "", st.ModTime().UTC(), false
111		}
112		var settings struct {
113			Security struct {
114				Auth struct {
115					SelectedType string `json:"selectedType"`
116				} `json:"auth"`
117			} `json:"security"`
118		}
119		if err := json.Unmarshal(data, &settings); err != nil {
120			return "", st.ModTime().UTC(), false
121		}
122		return strings.TrimSpace(settings.Security.Auth.SelectedType), st.ModTime().UTC(), true
123	}
124	
125	func readOAuthEvidence(dir, authType string, settingsTime, now time.Time) authSnapshot {
126		oauthPath := filepath.Join(dir, "oauth_creds.json")
127		st, err := os.Stat(oauthPath)
128		if err != nil || st.IsDir() {
129			return authSnapshot{
130				AuthType:   authType,
131				Source:     oauthPath,
132				CapturedAt: settingsTime,
133				Fresh:      isFresh(settingsTime, now),
134				Detail:     "Gemini OAuth credentials are missing",
135			}
136		}
137		data, err := safefs.ReadFile(oauthPath)
138		if err != nil {
139			return authSnapshot{
140				AuthType:   authType,
141				Source:     oauthPath,
142				CapturedAt: st.ModTime().UTC(),
143				Fresh:      isFresh(st.ModTime(), now),
144				Detail:     "Gemini OAuth credentials could not be read",
145			}
146		}
147		var creds struct {
148			AccessToken  string `json:"access_token"`
149			RefreshToken string `json:"refresh_token"`
150			ExpiryDate   int64  `json:"expiry_date"`
151		}
152		if err := json.Unmarshal(data, &creds); err != nil {
153			return authSnapshot{
154				AuthType:   authType,
155				Source:     oauthPath,
156				CapturedAt: st.ModTime().UTC(),
157				Fresh:      isFresh(st.ModTime(), now),
158				Detail:     "Gemini OAuth credentials are malformed",
159			}
160		}
161		authenticated := creds.RefreshToken != "" || creds.AccessToken != ""
162		if creds.ExpiryDate > 0 && creds.RefreshToken == "" {
163			expires := time.UnixMilli(creds.ExpiryDate)
164			authenticated = authenticated && expires.After(now)
165		}
166		capturedAt := maxTime(settingsTime, st.ModTime().UTC())
167		return authSnapshot{
168			Authenticated: authenticated,
169			AuthType:      authType,
170			Account:       readGoogleAccount(dir),
171			CapturedAt:    capturedAt,
172			Fresh:         isFresh(capturedAt, now),
173			Source:        oauthPath,
174			Detail:        oauthDetail(authenticated),
175		}
176	}
177	
178	func readGoogleAccount(dir string) *harnesses.AccountInfo {
179		data, err := safefs.ReadFile(filepath.Join(dir, "google_accounts.json"))
180		if err != nil {
181			return &harnesses.AccountInfo{PlanType: "Gemini OAuth"}
182		}
183		var accounts struct {
184			Active string `json:"active"`
185		}
186		if err := json.Unmarshal(data, &accounts); err != nil {
187			return &harnesses.AccountInfo{PlanType: "Gemini OAuth"}
188		}
189		account := &harnesses.AccountInfo{PlanType: "Gemini OAuth"}
190		if strings.Contains(accounts.Active, "@") {
191			account.Email = accounts.Active
192		}
193		return account
194	}
195	
196	func accountForAuthType(authType string) *harnesses.AccountInfo {
197		switch authType {
198		case authTypeGeminiAPIKey:
199			return &harnesses.AccountInfo{PlanType: "Gemini API key"}
200		case authTypeVertexAI:
201			return &harnesses.AccountInfo{PlanType: "Vertex AI"}
202		case authTypeComputeADC:
203			return &harnesses.AccountInfo{PlanType: "Google ADC"}
204		case authTypeGateway:
205			return &harnesses.AccountInfo{PlanType: "Gemini gateway"}
206		default:
207			return &harnesses.AccountInfo{PlanType: authType}
208		}
209	}
210	
211	func authTypeFromEnv() string {
212		if os.Getenv("GOOGLE_GENAI_USE_GCA") != "" {
213			return authTypeGateway
214		}
215		if os.Getenv("GOOGLE_GENAI_USE_VERTEXAI") != "" {
216			return authTypeVertexAI
217		}
218		if os.Getenv("GOOGLE_API_KEY") != "" || os.Getenv("GEMINI_API_KEY") != "" {
219			return authTypeGeminiAPIKey
220		}
221		if os.Getenv("CLOUD_SHELL") == "true" || os.Getenv("GEMINI_CLI_USE_COMPUTE_ADC") == "true" {
222			return authTypeComputeADC
223		}
224		return ""
225	}
226	
227	func oauthDetail(authenticated bool) string {
228		if authenticated {
229			return "Gemini OAuth credentials found; token values are not retained"
230		}
231		return "Gemini OAuth credentials do not contain usable token metadata"
232	}
233	
234	func isFresh(capturedAt, now time.Time) bool {
235		if capturedAt.IsZero() {
236			return false
237		}
238		return now.Sub(capturedAt) <= geminiAuthFreshnessWindow
239	}
240	
241	func maxTime(a, b time.Time) time.Time {
242		if a.After(b) {
243			return a
244		}
245		return b
246	}
