1	package gemini
2	
3	import (
4		"context"
5		"strings"
6		"time"
7	
8		"golang.org/x/sync/singleflight"
9	
10		"github.com/easel/fizeau/internal/harnesses"
11	)
12	
13	// geminiQuotaFreshness is the constant freshness window for gemini quota
14	// evidence. Mirrors defaultGeminiQuotaStaleAfter; kept as a separate name
15	// so the CONTRACT-004 method has a stable, contract-named constant.
16	const geminiQuotaFreshness = defaultGeminiQuotaStaleAfter
17	
18	// geminiAccountFreshness is the constant freshness window for gemini
19	// account/auth evidence. Gemini auth (~/.gemini OAuth and friends) rotates
20	// on a much slower cadence than quota; the scheduler runs it on its own
21	// 7-day ticker.
22	const geminiAccountFreshness = geminiAuthFreshnessWindow
23	
24	// supportedLimitIDs is the stable public set of Windows[].LimitID values
25	// gemini's /model manage probe emits. One per tier surfaced by the
26	// CLI dialog. Mirrored in doc.go for human readers.
27	var supportedLimitIDs = []string{
28		"gemini-pro",
29		"gemini-flash",
30		"gemini-flash-lite",
31	}
32	
33	// supportedAliases is the stable public set of family aliases
34	// ResolveModelAlias recognizes. Concrete tier names (e.g.
35	// "gemini-2.5-flash") are not aliases — they pass through unchanged
36	// when the routing layer requests them. Mirrored in doc.go.
37	var supportedAliases = []string{
38		"gemini",
39		"gemini-2",
40		"gemini-2.5",
41	}
42	
43	// refreshGroup serializes concurrent RefreshQuota / RefreshAccount calls
44	// across all *Runner instances. Per CONTRACT-004 invariant #6 Runners are
45	// stateless wrappers — sharing the singleflight group at package scope
46	// keeps single-flight semantics correct when callers construct fresh
47	// runner instances per call.
48	var refreshGroup singleflight.Group
49	
50	// QuotaStatus implements harnesses.QuotaHarness. It reads the cached
51	// snapshot owned by this harness and projects it onto QuotaStatus. A
52	// missing or undecodable cache is reported as State=QuotaUnavailable on
53	// a valid QuotaStatus value (no error) per CONTRACT-004 §"Errors are
54	// reserved for call failure."
55	func (r *Runner) QuotaStatus(ctx context.Context, now time.Time) (harnesses.QuotaStatus, error) {
56		if err := ctx.Err(); err != nil {
57			return harnesses.QuotaStatus{}, err
58		}
59		snap, ok := readGeminiQuota()
60		if !ok || snap == nil {
61			return harnesses.QuotaStatus{
62				Source:            "cache",
63				State:             harnesses.QuotaUnavailable,
64				RoutingPreference: harnesses.RoutingPreferenceUnknown,
65				Reason:            "no cached snapshot",
66			}, nil
67		}
68		return geminiQuotaStatusFromSnapshot(snap, now), nil
69	}
70	
71	// RefreshQuota implements harnesses.QuotaHarness. It probes the gemini
72	// CLI via PTY unconditionally and persists the result through the
73	// harness's owned cache. Single-flight per package: concurrent callers
74	// share one cohort and observe the just-written cached state. Probe
75	// failure (binary missing, PTY error, parse failure) is reported as
76	// State=QuotaUnavailable on a valid QuotaStatus value, not as an error.
77	func (r *Runner) RefreshQuota(ctx context.Context) (harnesses.QuotaStatus, error) {
78		if err := ctx.Err(); err != nil {
79			return harnesses.QuotaStatus{}, err
80		}
81		v, err, _ := refreshGroup.Do("gemini:refresh-quota", func() (any, error) {
82			return r.refreshQuotaLocked(ctx), nil
83		})
84		if err != nil {
85			return harnesses.QuotaStatus{}, err
86		}
87		return v.(harnesses.QuotaStatus), nil
88	}
89	
90	// refreshQuotaLocked is the single-flight critical section. It probes
91	// PTY, writes the cache on success, and returns the projected status.
92	// Probe failure is folded into State=QuotaUnavailable.
93	func (r *Runner) refreshQuotaLocked(ctx context.Context) harnesses.QuotaStatus {
94		now := time.Now()
95		timeout := geminiQuotaFreshness
96		if deadline, ok := ctx.Deadline(); ok {
97			remaining := time.Until(deadline)
98			if remaining > 0 && remaining < timeout {
99				timeout = remaining
100			}
101		}
102		var opts []QuotaPTYOption
103		if r.Binary != "" {
104			opts = append(opts, WithQuotaPTYCommand(r.Binary))
105		}
106		windows, _, err := captureGeminiQuotaViaPTY(ctx, timeout, opts...)
107		if err != nil {
108			state := harnesses.QuotaUnavailable
109			reason := err.Error()
110			lower := strings.ToLower(reason)
111			switch {
112			case strings.Contains(lower, "not found") || strings.Contains(lower, "executable file not found"):
113				state = harnesses.QuotaUnavailable
114			case strings.Contains(lower, "unauth") || strings.Contains(lower, "credential"):
115				state = harnesses.QuotaUnauthenticated
116			}
117			return harnesses.QuotaStatus{
118				Source:            "pty",
119				CapturedAt:        now.UTC(),
120				State:             state,
121				RoutingPreference: harnesses.RoutingPreferenceUnknown,
122				Reason:            reason,
123			}
124		}
125		account := readAuthEvidence(now).Account
126		snap := geminiQuotaSnapshot{
127			CapturedAt: now.UTC(),
128			Windows:    windows,
129			Source:     "pty",
130			Account:    account,
131		}
132		if path, pathErr := geminiQuotaCachePath(); pathErr == nil {
133			_ = writeGeminiQuota(path, snap)
134		}
135		return geminiQuotaStatusFromSnapshot(&snap, now)
136	}
137	
138	// QuotaFreshness implements harnesses.QuotaHarness.
139	func (r *Runner) QuotaFreshness() time.Duration {
140		return geminiQuotaFreshness
141	}
142	
143	// SupportedLimitIDs implements harnesses.QuotaHarness.
144	func (r *Runner) SupportedLimitIDs() []string {
145		return append([]string(nil), supportedLimitIDs...)
146	}
147	
148	// AccountStatus implements harnesses.AccountHarness. Gemini's account
149	// state is sourced from authSnapshot (read from ~/.gemini and env).
150	func (r *Runner) AccountStatus(ctx context.Context, now time.Time) (harnesses.AccountSnapshot, error) {
151		if err := ctx.Err(); err != nil {
152			return harnesses.AccountSnapshot{}, err
153		}
154		auth := readAuthEvidence(now)
155		return geminiAccountSnapshotFromAuth(auth), nil
156	}
157	
158	// RefreshAccount implements harnesses.AccountHarness. readAuthEvidence
159	// is filesystem-only (no network probe), so refresh is the same call as
160	// status. Single-flight on the package's refresh group keeps concurrent
161	// callers consistent with the QuotaHarness contract shape.
162	func (r *Runner) RefreshAccount(ctx context.Context) (harnesses.AccountSnapshot, error) {
163		if err := ctx.Err(); err != nil {
164			return harnesses.AccountSnapshot{}, err
165		}
166		v, err, _ := refreshGroup.Do("gemini:refresh-account", func() (any, error) {
167			auth := readAuthEvidence(time.Now())
168			return geminiAccountSnapshotFromAuth(auth), nil
169		})
170		if err != nil {
171			return harnesses.AccountSnapshot{}, err
172		}
173		return v.(harnesses.AccountSnapshot), nil
174	}
175	
176	// AccountFreshness implements harnesses.AccountHarness. Gemini auth
177	// rotates on a 7-day cadence, decoupled from the 15-minute quota
178	// cadence — the refresh scheduler runs them on independent tickers.
179	func (r *Runner) AccountFreshness() time.Duration {
180		return geminiAccountFreshness
181	}
182	
183	// DefaultModelSnapshot implements harnesses.ModelDiscoveryHarness.
184	func (r *Runner) DefaultModelSnapshot() harnesses.ModelDiscoverySnapshot {
185		return defaultGeminiModelDiscovery()
186	}
187	
188	// ResolveModelAlias implements harnesses.ModelDiscoveryHarness. Returns
189	// harnesses.ErrAliasNotResolvable when the supplied family is not a
190	// recognized gemini alias or when the discovery snapshot has no concrete
191	// model matching the family.
192	func (r *Runner) ResolveModelAlias(family string, snapshot harnesses.ModelDiscoverySnapshot) (string, error) {
193		normalized := strings.ToLower(strings.TrimSpace(family))
194		if !isSupportedGeminiAlias(normalized) {
195			return "", harnesses.ErrAliasNotResolvable
196		}
197		resolved := resolveGeminiModelAlias(normalized, snapshot)
198		if resolved == "" || resolved == normalized {
199			// resolveGeminiModelAlias returns the input unchanged when no
200			// concrete model matches. Treat that as not-resolvable so the
201			// CONTRACT-004 negative-path semantics are preserved.
202			return "", harnesses.ErrAliasNotResolvable
203		}
204		return resolved, nil
205	}
206	
207	// SupportedAliases implements harnesses.ModelDiscoveryHarness.
208	func (r *Runner) SupportedAliases() []string {
209		return append([]string(nil), supportedAliases...)
210	}
211	
212	func isSupportedGeminiAlias(family string) bool {
213		for _, a := range supportedAliases {
214			if a == family {
215				return true
216			}
217		}
218		return false
219	}
220	
221	// geminiQuotaStatusFromSnapshot projects the per-harness snapshot onto
222	// harnesses.QuotaStatus, deriving State and RoutingPreference via the
223	// existing decideGeminiQuotaRouting helper. Tier facts (Flash / Flash
224	// Lite / Pro) live in Windows with their distinguishing LimitID; no tier
225	// names appear in Detail.
226	func geminiQuotaStatusFromSnapshot(snap *geminiQuotaSnapshot, now time.Time) harnesses.QuotaStatus {
227		decision := decideGeminiQuotaRouting(snap, now, geminiQuotaFreshness)
228		pref, state := mapGeminiRoutingPreference(decision)
229		status := harnesses.QuotaStatus{
230			Source:            snap.Source,
231			CapturedAt:        snap.CapturedAt,
232			Fresh:             decision.fresh,
233			Age:               decision.age,
234			State:             state,
235			Windows:           append([]harnesses.QuotaWindow(nil), snap.Windows...),
236			RoutingPreference: pref,
237			Reason:            decision.reason,
238		}
239		if snap.Account != nil {
240			acct := harnesses.AccountSnapshot{
241				Source:     "cache",
242				CapturedAt: snap.CapturedAt,
243				Fresh:      isGeminiQuotaFresh(snap, now, geminiAccountFreshness),
244				PlanType:   snap.Account.PlanType,
245				Email:      snap.Account.Email,
246				OrgName:    snap.Account.OrgName,
247			}
248			if snap.Account.PlanType != "" || snap.Account.Email != "" {
249				acct.Authenticated = true
250			}
251			status.Account = &acct
252		}
253		return status
254	}
255	
256	// mapGeminiRoutingPreference translates today's preferGemini+freshness
257	// decision into the CONTRACT-004 (RoutingPreference, QuotaStateValue)
258	// pair. Legacy semantics: missing snapshot ⇒ Unavailable/Unknown;
259	// stale ⇒ Stale/Blocked ("assume limited"); fresh+preferGemini ⇒
260	// OK/Available; fresh+!preferGemini ⇒ Blocked/Blocked.
261	func mapGeminiRoutingPreference(d geminiQuotaRoutingDecision) (harnesses.RoutingPreference, harnesses.QuotaStateValue) {
262		if !d.snapshotPresent {
263			return harnesses.RoutingPreferenceUnknown, harnesses.QuotaUnavailable
264		}
265		if !d.fresh {
266			return harnesses.RoutingPreferenceBlocked, harnesses.QuotaStale
267		}
268		if d.preferGemini {
269			return harnesses.RoutingPreferenceAvailable, harnesses.QuotaOK
270		}
271		return harnesses.RoutingPreferenceBlocked, harnesses.QuotaBlocked
272	}
273	
274	// geminiAccountSnapshotFromAuth projects an authSnapshot onto the
275	// universal AccountSnapshot type. Authenticated is true iff the
276	// underlying auth evidence reports an authenticated session;
277	// Unauthenticated is the explicit negative signal so the projection
278	// distinguishes "no evidence" from "evidence says signed out".
279	func geminiAccountSnapshotFromAuth(auth authSnapshot) harnesses.AccountSnapshot {
280		out := harnesses.AccountSnapshot{
281			Source:     auth.Source,
282			CapturedAt: auth.CapturedAt,
283			Fresh:      auth.Fresh,
284			Detail:     auth.Detail,
285		}
286		if auth.Account != nil {
287			out.PlanType = auth.Account.PlanType
288			out.Email = auth.Account.Email
289			out.OrgName = auth.Account.OrgName
290		}
291		if auth.Authenticated {
292			out.Authenticated = true
293		} else {
294			out.Unauthenticated = true
295		}
296		return out
297	}
298	
299	// Compile-time interface satisfaction.
300	var (
301		_ harnesses.Harness               = (*Runner)(nil)
302		_ harnesses.QuotaHarness          = (*Runner)(nil)
303		_ harnesses.AccountHarness        = (*Runner)(nil)
304		_ harnesses.ModelDiscoveryHarness = (*Runner)(nil)
305	)
