2	
3	import (
4		"encoding/json"
5		"fmt"
6		"os"
7		"path/filepath"
8		"strings"
9		"time"
10	
11		"github.com/easel/fizeau/internal/harnesses"
12		"github.com/easel/fizeau/internal/productinfo"
13		"github.com/easel/fizeau/internal/safefs"
14	)
15	
16	// geminiQuotaSnapshot captures parsed Gemini CLI /model manage quota evidence
17	// in a durable cache so foreground routing consumers do not invoke PTY
18	// capture inline.
19	//
20	// Auth/account freshness on its own is NOT quota evidence. Only a parsed
21	// geminiQuotaSnapshot with one or more tier windows promotes Gemini beyond
22	// the "quota unknown" state.
23	type geminiQuotaSnapshot struct {
24		CapturedAt time.Time               `json:"captured_at"`
25		Windows    []harnesses.QuotaWindow `json:"windows"`
26		Source     string                  `json:"source"` // e.g. "pty", "cassette"
27		Account    *harnesses.AccountInfo  `json:"account,omitempty"`
28		Detail     string                  `json:"detail,omitempty"`
29	}
30	
31	const defaultGeminiQuotaStaleAfter = 15 * time.Minute
32	
33	const geminiQuotaCacheEnv = "FIZEAU_GEMINI_QUOTA_CACHE"
34	
35	func geminiQuotaCachePath() (string, error) {
36		if path := os.Getenv(geminiQuotaCacheEnv); path != "" {
37			return path, nil
38		}
39		if xdg := os.Getenv("XDG_STATE_HOME"); xdg != "" {
40			return filepath.Join(xdg, productinfo.ConfigDir, "gemini-quota.json"), nil
41		}
42		home, err := os.UserHomeDir()
43		if err != nil {
44			return "", err
45		}
46		return filepath.Join(home, ".local", "state", productinfo.ConfigDir, "gemini-quota.json"), nil
47	}
48	
49	func writeGeminiQuota(path string, snapshot geminiQuotaSnapshot) error {
50		if path == "" {
51			return fmt.Errorf("gemini quota cache path is empty")
52		}
53		if snapshot.CapturedAt.IsZero() {
54			snapshot.CapturedAt = time.Now().UTC()
55		} else {
56			snapshot.CapturedAt = snapshot.CapturedAt.UTC()
57		}
58		if snapshot.Source == "" {
59			snapshot.Source = "pty"
60		}
61		if err := os.MkdirAll(filepath.Dir(path), 0o750); err != nil {
62			return fmt.Errorf("create gemini quota cache dir: %w", err)
63		}
64		data, err := json.MarshalIndent(snapshot, "", "  ")
65		if err != nil {
66			return fmt.Errorf("marshal gemini quota snapshot: %w", err)
67		}
68		data = append(data, '\n')
69		tmpPath := path + ".tmp"
70		if err := os.WriteFile(tmpPath, data, 0o600); err != nil {
71			return fmt.Errorf("write gemini quota cache tmp: %w", err)
72		}
73		if err := os.Rename(tmpPath, path); err != nil {
74			_ = os.Remove(tmpPath)
75			return fmt.Errorf("rename gemini quota cache: %w", err)
76		}
77		if err := os.Chmod(path, 0o600); err != nil {
78			return fmt.Errorf("chmod gemini quota cache: %w", err)
79		}
80		return nil
81	}
82	
83	func readGeminiQuotaFrom(path string) (*geminiQuotaSnapshot, bool) {
84		data, err := safefs.ReadFile(path)
85		if err != nil {
86			return nil, false
87		}
88		var snap geminiQuotaSnapshot
89		if err := json.Unmarshal(data, &snap); err != nil {
90			return nil, false
91		}
92		return &snap, true
93	}
94	
95	func readGeminiQuota() (*geminiQuotaSnapshot, bool) {
96		path, err := geminiQuotaCachePath()
97		if err != nil {
98			return nil, false
99		}
100		return readGeminiQuotaFrom(path)
101	}
102	
103	func geminiQuotaSnapshotAge(snapshot *geminiQuotaSnapshot, now time.Time) time.Duration {
104		if snapshot == nil || snapshot.CapturedAt.IsZero() {
105			return 0
106		}
107		age := now.UTC().Sub(snapshot.CapturedAt.UTC())
108		if age < 0 {
109			return 0
110		}
111		return age
112	}
113	
114	func isGeminiQuotaFresh(snapshot *geminiQuotaSnapshot, now time.Time, staleAfter time.Duration) bool {
115		if snapshot == nil || snapshot.CapturedAt.IsZero() {
116			return false
117		}
118		if staleAfter <= 0 {
119			staleAfter = defaultGeminiQuotaStaleAfter
120		}
121		return geminiQuotaSnapshotAge(snapshot, now) <= staleAfter
122	}
123	
124	type geminiQuotaRoutingDecision struct {
125		preferGemini    bool
126		snapshotPresent bool
127		fresh           bool
128		age             time.Duration
129		snapshot        *geminiQuotaSnapshot
130		availableTiers  []string
131		exhaustedTiers  []string
132		reason          string
133	}
134	
135	func decideGeminiQuotaRouting(snapshot *geminiQuotaSnapshot, now time.Time, staleAfter time.Duration) geminiQuotaRoutingDecision {
136		decision := geminiQuotaRoutingDecision{snapshot: snapshot}
137		if snapshot == nil {
138			decision.reason = "no cached gemini quota snapshot; assume limited"
139			return decision
140		}
141		decision.snapshotPresent = true
142		decision.age = geminiQuotaSnapshotAge(snapshot, now)
143		if !isGeminiQuotaFresh(snapshot, now, staleAfter) {
144			decision.reason = "cached gemini quota snapshot is stale; assume limited"
145			return decision
146		}
147		decision.fresh = true
148		if len(snapshot.Windows) == 0 {
149			decision.reason = "fresh gemini quota snapshot has no tier windows; assume limited"
150			return decision
151		}
152		for _, w := range snapshot.Windows {
153			if isExhaustedWindow(w) {
154				decision.exhaustedTiers = append(decision.exhaustedTiers, w.LimitID)
155				continue
156			}
157			decision.availableTiers = append(decision.availableTiers, w.LimitID)
158		}
159		if len(decision.availableTiers) == 0 {
160			decision.reason = "fresh gemini quota snapshot reports all tiers exhausted; assume limited"
161			return decision
162		}
163		decision.preferGemini = true
164		decision.reason = "fresh gemini quota snapshot has at least one tier with headroom"
165		return decision
166	}
167	
168	func (d geminiQuotaRoutingDecision) isGeminiTierAvailable(model string) bool {
169		if !d.preferGemini {
170			return false
171		}
172		limitID, ok := TierLimitIDForModel(model)
173		if !ok {
174			return false
175		}
176		for _, tier := range d.availableTiers {
177			if tier == limitID {
178				return true
179			}
180		}
181		return false
182	}
183	
184	func (s *geminiQuotaSnapshot) maxUsedPercent() float64 {
185		if s == nil {
186			return 0
187		}
188		max := 0.0
189		for _, w := range s.Windows {
190			if w.UsedPercent > max {
191				max = w.UsedPercent
192			}
193		}
194		return max
195	}
196	
197	func isExhaustedWindow(w harnesses.QuotaWindow) bool {
198		if strings.EqualFold(w.State, "exhausted") || strings.EqualFold(w.State, "blocked") {
199			return true
200		}
201		return w.UsedPercent >= 95
202	}
