2	
3	import (
4		"context"
5		"fmt"
6		"time"
7	
8		"github.com/easel/fizeau/internal/harnesses"
9		"github.com/easel/fizeau/internal/harnesses/ptyquota"
10		"github.com/easel/fizeau/internal/pty/cassette"
11		"github.com/easel/fizeau/internal/pty/session"
12	)
13	
14	type quotaPTYOptions struct {
15		binary      string
16		args        []string
17		workdir     string
18		env         []string
19		cassetteDir string
20	}
21	
22	// QuotaPTYOption configures a Gemini quota PTY probe.
23	type QuotaPTYOption func(*quotaPTYOptions)
24	
25	func WithQuotaPTYCommand(binary string, args ...string) QuotaPTYOption {
26		return func(opts *quotaPTYOptions) {
27			opts.binary = binary
28			opts.args = append([]string(nil), args...)
29		}
30	}
31	
32	func WithQuotaPTYWorkdir(workdir string) QuotaPTYOption {
33		return func(opts *quotaPTYOptions) {
34			opts.workdir = workdir
35		}
36	}
37	
38	func WithQuotaPTYEnv(env ...string) QuotaPTYOption {
39		return func(opts *quotaPTYOptions) {
40			opts.env = append([]string(nil), env...)
41		}
42	}
43	
44	func WithQuotaPTYCassetteDir(dir string) QuotaPTYOption {
45		return func(opts *quotaPTYOptions) {
46			opts.cassetteDir = dir
47		}
48	}
49	
50	// ReadGeminiQuotaViaPTY launches Gemini, sends /model manage, and returns the
51	// parsed tier quota windows. Callers must only treat non-empty, non-error
52	// results as authoritative — Gemini CLI renders /model manage as a version-
53	// sensitive TUI, so a timeout or empty parse means "quota unknown".
54	func ReadGeminiQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, error) {
55		windows, _, err := captureGeminiQuotaViaPTY(context.Background(), timeout, opts...)
56		return windows, err
57	}
58	
59	// ReadGeminiQuotaFromCassette replays a previously recorded cassette and
60	// re-parses its final frame as Gemini /model manage output.
61	func ReadGeminiQuotaFromCassette(dir string) ([]harnesses.QuotaWindow, error) {
62		reader, err := cassette.Open(dir)
63		if err != nil {
64			return nil, err
65		}
66		text := reader.Final().FinalText
67		if text == "" {
68			frames := reader.Frames()
69			if len(frames) > 0 {
70				text = stringsJoinLines(frames[len(frames)-1].Text)
71			}
72		}
73		windows := ParseGeminiModelManage(text)
74		if len(windows) == 0 {
75			return nil, fmt.Errorf("no gemini tier quota windows found in cassette")
76		}
77		return windows, nil
78	}
79	
80	func captureGeminiQuotaViaPTY(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, ptyquota.Result, error) {
81		cfg := quotaPTYOptions{binary: "gemini"}
82		for _, opt := range opts {
83			if opt != nil {
84				opt(&cfg)
85			}
86		}
87		var windows []harnesses.QuotaWindow
88		result, err := ptyquota.Run(ctx, ptyquota.Config{
89			HarnessName:  "gemini",
90			Binary:       cfg.binary,
91			Args:         cfg.args,
92			Workdir:      cfg.workdir,
93			Env:          cfg.env,
94			Command:      "/model manage\r",
95			ReadyMarkers: []string{">", "❯"},
96			DoneWhen:     geminiQuotaComplete,
97			Timeout:      timeout,
98			Size:         session.Size{Rows: 50, Cols: 220},
99			CassetteDir:  cfg.cassetteDir,
100			Quota: func(text string) (cassette.QuotaRecord, error) {
101				windows = ParseGeminiModelManage(text)
102				if len(windows) == 0 {
103					return cassette.QuotaRecord{}, fmt.Errorf("no gemini tier quota windows found in /model manage output")
104				}
105				return geminiQuotaRecord(windows), nil
106			},
107		})
108		if err != nil {
109			return nil, result, err
110		}
111		if len(windows) == 0 {
112			windows = ParseGeminiModelManage(result.Text)
113		}
114		if len(windows) == 0 {
115			return nil, result, fmt.Errorf("no gemini tier quota windows found in /model manage output")
116		}
117		return windows, result, nil
118	}
119	
120	// geminiQuotaComplete is the probe's DoneWhen predicate. Gemini CLI renders
121	// tiers one by one as the dialog loads. Waiting for at least one tier with a
122	// parsed "% used" token is enough: tiers that never appear in the rendered
123	// dialog were not surfaced by this CLI version.
124	func geminiQuotaComplete(text string) bool {
125		windows := ParseGeminiModelManage(text)
126		return len(windows) >= 1
127	}
128	
129	func geminiQuotaRecord(windows []harnesses.QuotaWindow) cassette.QuotaRecord {
130		records := make([]map[string]any, 0, len(windows))
131		for _, window := range windows {
132			records = append(records, map[string]any{
133				"name":         window.Name,
134				"limit_id":     window.LimitID,
135				"used_percent": window.UsedPercent,
136				"resets_at":    window.ResetsAt,
137				"state":        window.State,
138			})
139		}
140		return cassette.QuotaRecord{
141			Source:            "pty",
142			Status:            string(ptyquota.StatusOK),
143			CapturedAt:        time.Now().UTC().Format(time.RFC3339),
144			FreshnessWindow:   defaultGeminiQuotaStaleAfter.String(),
145			StalenessBehavior: "stale gemini quota evidence keeps Gemini out of automatic routing and is treated as limited",
146			Windows:           records,
147		}
148	}
149	
150	func stringsJoinLines(lines []string) string {
151		out := ""
152		for i, line := range lines {
153			if i > 0 {
154				out += "\n"
155			}
156			out += line
157		}
158		return out
159	}
