1	package gemini
2	
3	import (
4		"context"
5		"encoding/json"
6		"errors"
7		"fmt"
8		"io"
9		"os"
10		osexec "os/exec"
11		"strings"
12		"syscall"
13		"time"
14	
15		"github.com/easel/fizeau/internal/harnesses"
16	)
17	
18	const defaultEventBuffer = 64
19	
20	// Runner is the subprocess-backed gemini harness. It launches gemini in
21	// headless mode (-p/--prompt), buffers stream-json stdout, and emits
22	// text_delta + final events after the process exits.
23	//
24	// When the output is valid JSON with a stats.models token block, usage is
25	// extracted per the DDx ExtractUsage("gemini", ...) shape.
26	type Runner struct {
27		// Binary is the absolute path to the gemini executable. When empty the
28		// runner resolves "gemini" via PATH at Execute time.
29		Binary string
30	
31		// BaseArgs is prepended to the per-request argument list.
32		// Gemini default: ["--output-format", "stream-json"].
33		BaseArgs []string
34	
35		// PromptMode controls how the prompt is delivered.
36		// "arg" (default) sends "-p <prompt>"; "stdin" sends "-p ''" and writes
37		// the prompt to stdin. Gemini requires -p/--prompt for headless mode.
38		PromptMode string
39	
40		// EventBuffer overrides the per-Execute channel buffer size.
41		EventBuffer int
42	}
43	
44	// Info returns identity + capability metadata for this harness.
45	func (r *Runner) Info() harnesses.HarnessInfo {
46		info := harnesses.HarnessInfo{
47			Name:                 "gemini",
48			Type:                 "subprocess",
49			IsLocal:              false,
50			IsSubscription:       true,
51			AutoRoutingEligible:  false,
52			ExactPinSupport:      true,
53			DefaultModel:         "gemini-2.5-flash",
54			SupportedPermissions: []string{"safe", "supervised", "unrestricted"},
55			SupportedReasoning:   nil,
56			CostClass:            "medium",
57		}
58		path := r.Binary
59		if path == "" {
60			if resolved, err := osexec.LookPath("gemini"); err == nil {
61				path = resolved
62			}
63		}
64		if path != "" {
65			info.Path = path
66			info.Available = true
67		} else {
68			info.Error = "gemini binary not found in PATH"
69		}
70		return info
71	}
72	
73	// HealthCheck verifies the gemini binary is present.
74	func (r *Runner) HealthCheck(ctx context.Context) error {
75		if err := ctx.Err(); err != nil {
76			return err
77		}
78		path := r.Binary
79		if path == "" {
80			resolved, err := osexec.LookPath("gemini")
81			if err != nil {
82				return fmt.Errorf("gemini binary not found: %w", err)
83			}
84			path = resolved
85		}
86		st, err := os.Stat(path)
87		if err != nil {
88			return fmt.Errorf("stat gemini binary: %w", err)
89		}
90		if st.IsDir() {
91			return fmt.Errorf("gemini binary path is a directory: %s", path)
92		}
93		return nil
94	}
95	
96	// Execute runs one resolved request through the gemini CLI and emits events
97	// on the returned channel. Since gemini has no stream-json mode, events are
98	// emitted after the process exits (emit-on-EOF pattern).
99	func (r *Runner) Execute(ctx context.Context, req harnesses.ExecuteRequest) (<-chan harnesses.Event, error) {
100		binary := r.Binary
101		if binary == "" {
102			resolved, err := osexec.LookPath("gemini")
103			if err != nil {
104				return nil, fmt.Errorf("gemini binary not found: %w", err)
105			}
106			binary = resolved
107		}
108	
109		bufSize := r.EventBuffer
110		if bufSize <= 0 {
111			bufSize = defaultEventBuffer
112		}
113	
114		out := make(chan harnesses.Event, bufSize)
115		go r.run(ctx, binary, req, out)
116		return out, nil
117	}
118	
119	func (r *Runner) run(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event) {
120		defer close(out)
121	
122		start := time.Now()
123		var seq int64
124	
125		agg, exitCode, stderr, runErr, status := r.runBuffered(ctx, binary, req, out, &seq)
126	
127		final := harnesses.FinalData{
128			Status:     status,
129			ExitCode:   exitCode,
130			DurationMS: time.Since(start).Milliseconds(),
131		}
132		if runErr != nil && status != "success" {
133			final.Error = runErr.Error()
134		} else if stderr != "" && status != "success" {
135			final.Error = trimErrorBlob(stderr)
136		}
137		if agg != nil {
138			final.FinalText = agg.FinalText
139			if agg.HasUsage {
140				final.Usage = &harnesses.FinalUsage{
141					InputTokens:  harnesses.IntPtr(agg.InputTokens),
142					OutputTokens: harnesses.IntPtr(agg.OutputTokens),
143					Source:       harnesses.UsageSourceNativeStream,
144					Fresh:        harnesses.BoolPtr(true),
145				}
146				if agg.TotalTokens > 0 {
147					final.Usage.TotalTokens = harnesses.IntPtr(agg.TotalTokens)
148				} else {
149					final.Usage.TotalTokens = harnesses.IntPtr(agg.InputTokens + agg.OutputTokens)
150				}
151				if agg.CacheTokens > 0 {
152					final.Usage.CacheTokens = harnesses.IntPtr(agg.CacheTokens)
153				}
154			}
155			if agg.CostUSD > 0 {
156				final.CostUSD = agg.CostUSD
157			}
158		}
159	
160		finalRaw, err := json.Marshal(final)
161		if err != nil {
162			finalRaw = []byte(`{"status":"failed","error":"marshal final event"}`)
163		}
164		ev := harnesses.Event{
165			Type:     harnesses.EventTypeFinal,
166			Sequence: seq,
167			Time:     time.Now().UTC(),
168			Metadata: req.Metadata,
169			Data:     finalRaw,
170		}
171		select {
172		case out <- ev:
173		case <-time.After(time.Second):
174		}
175	}
176	
177	func (r *Runner) runBuffered(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event, seq *int64) (agg *streamAggregate, exitCode int, stderr string, runErr error, status string) {
178		base := r.BaseArgs
179		if base == nil {
180			base = []string{"--output-format", "stream-json"}
181		}
182		args := append([]string{}, base...)
183	
184		// Model flag: -m <model>
185		if req.Model != "" {
186			args = append(args, "-m", req.Model)
187		}
188	
189		switch req.Permissions {
190		case "", "safe":
191			args = append(args, "--approval-mode", "plan")
192		case "supervised":
193			args = append(args, "--approval-mode", "default")
194		case "unrestricted":
195			args = append(args, "--approval-mode", "yolo")
196		}
197	
198		if value := harnesses.AdapterReasoningValue(req); value != "" {
199			return nil, -1, "", fmt.Errorf("gemini reasoning control %q is not supported by the CLI harness", value), "failed"
200		}
201	
202		promptMode := r.PromptMode
203		if promptMode == "" {
204			promptMode = "arg"
205		}
206		switch promptMode {
207		case "arg":
208			args = append(args, "-p", req.Prompt)
209		case "stdin":
210			args = append(args, "-p", "")
211		default:
212			return nil, -1, "", fmt.Errorf("unsupported gemini prompt mode %q", promptMode), "failed"
213		}
214	
215		runCtx, cancel := context.WithCancel(ctx)
216		defer cancel()
217	
218		cmd := harnesses.HarnessCommand(runCtx, binary, args...)
219		if req.WorkDir != "" {
220			cmd.Dir = req.WorkDir
221		}
222		if promptMode == "stdin" {
223			cmd.Stdin = strings.NewReader(req.Prompt)
224		}
225		setProcessGroup(cmd)
226	
227		stdoutPipe, err := cmd.StdoutPipe()
228		if err != nil {
229			return nil, -1, "", err, "failed"
230		}
231		stderrPipe, err := cmd.StderrPipe()
232		if err != nil {
233			return nil, -1, "", err, "failed"
234		}
235	
236		if err := cmd.Start(); err != nil {
237			return nil, -1, "", err, "failed"
238		}
239	
240		progressLog, _ := harnesses.OpenProgressLog(req.SessionLogDir, req.SessionID, "gemini")
241		if progressLog != nil {
242			defer progressLog.Close()
243		}
244	
245		// Buffer stdout; emit after process exits (no streaming parser for gemini).
246		var stdoutBytes []byte
247		stdoutReady := make(chan struct{})
248		go func() {
249			defer close(stdoutReady)
250			stdoutBytes, _ = io.ReadAll(stdoutPipe)
251		}()
252	
253		var stderrBuf strings.Builder
254		stderrDone := make(chan struct{})
255		go func() {
256			defer close(stderrDone)
257			_, _ = io.Copy(&stringBuilderWriter{&stderrBuf}, stderrPipe)
258		}()
259	
260		var timedOut bool
261		if req.Timeout > 0 {
262			stop := make(chan struct{})
263			go func() {
264				select {
265				case <-stop:
266				case <-time.After(req.Timeout):
267					timedOut = true
268					cancel()
269				}
270			}()
271			defer close(stop)
272		}
273	
274		cancelDone := make(chan struct{})
275		go func() {
276			defer close(cancelDone)
277			select {
278			case <-ctx.Done():
279				killProcessGroup(cmd)
280			case <-stdoutReady:
281			}
282		}()
283	
284		<-stdoutReady
285		<-stderrDone
286		runErr = cmd.Wait()
287		<-cancelDone
288		stderr = stderrBuf.String()
289	
290		switch {
291		case timedOut:
292			return nil, -1, stderr, context.DeadlineExceeded, "timed_out"
293		case ctx.Err() != nil && errors.Is(ctx.Err(), context.Canceled):
294			return nil, -1, stderr, ctx.Err(), "cancelled"
295		case ctx.Err() != nil && errors.Is(ctx.Err(), context.DeadlineExceeded):
296			return nil, -1, stderr, ctx.Err(), "timed_out"
297		case runErr != nil:
298			ec := -1
299			var exitErr *osexec.ExitError
300			if errors.As(runErr, &exitErr) {
301				ec = exitErr.ExitCode()
302			}
303			return nil, ec, stderr, runErr, "failed"
304		}
305	
306		// Parse buffered output and emit events.
307		output := strings.TrimSpace(string(stdoutBytes))
308		parseAgg, parseErr := emitGeminiOutput(ctx, output, out, req.Metadata, seq, progressLog)
309		if parseErr != nil && !errors.Is(parseErr, context.Canceled) {
310			return parseAgg, 0, stderr, parseErr, "failed"
311		}
312		return parseAgg, 0, stderr, nil, "success"
313	}
314	
315	// emitGeminiOutput parses buffered gemini output, emits a text_delta, and
316	// extracts token usage from the JSON stats block if present.
317	func emitGeminiOutput(ctx context.Context, output string, out chan<- harnesses.Event, metadata map[string]string, seq *int64, progressLog *os.File) (*streamAggregate, error) {
318		agg := &streamAggregate{}
319		if output == "" {
320			return agg, nil
321		}
322	
323		if msg := geminiStreamError(output); msg != "" {
324			return agg, errors.New("gemini error: " + msg)
325		}
326	
327		if parsed, ok := parseGeminiStreamOutput(output); ok {
328			agg = parsed
329			if agg.FinalText == "" {
330				return agg, nil
331			}
332		} else {
333			// Legacy/fallback: extract usage from a trailing stats block and emit
334			// the raw text exactly as the CLI returned it.
335			agg = parseGeminiUsage(output)
336		}
337	
338		raw, err := json.Marshal(harnesses.TextDeltaData{Text: agg.FinalText})
339		if err != nil {
340			return agg, err
341		}
342		ev := harnesses.Event{
343			Type:     harnesses.EventTypeTextDelta,
344			Sequence: *seq,
345			Time:     time.Now().UTC(),
346			Metadata: metadata,
347			Data:     raw,
348		}
349		*seq++
350	
351		harnesses.WriteProgressEvent(progressLog, ev)
352	
353		select {
354		case out <- ev:
355		case <-ctx.Done():
356			return agg, ctx.Err()
357		}
358		return agg, nil
359	}
