378	func setProcessGroup(cmd *osexec.Cmd) {
379		if cmd.SysProcAttr == nil {
380			cmd.SysProcAttr = &syscall.SysProcAttr{}
381		}
382		setProcessGroupAttr(cmd.SysProcAttr)
383	}
