37	// TestRunner_Execute_HappyPath runs a fake script that emits gemini-style output.
38	func TestRunner_Execute_HappyPath(t *testing.T) {
39		if _, err := exec.LookPath("sh"); err != nil {
40			t.Skip("sh not available")
41		}
42	
43		// Gemini emits stream-json lines in headless mode.
44		script := `#!/bin/sh
45	cat <<'EOF'
46	skill conflict warning from stdout
47	{"type":"init","session_id":"test","model":"gemini-2.0-flash"}
48	{"type":"message","role":"user","content":"test prompt"}
49	{"type":"message","role":"assistant","content":"Hello from gemini","delta":true}
50	{"type":"result","status":"success","stats":{"total_tokens":25,"input_tokens":12,"output_tokens":13,"cached":2,"models":{"gemini-2.0-flash":{"total_tokens":25,"input_tokens":12,"output_tokens":13,"cached":2}}}}
51	EOF
52	`
53		f, err := os.CreateTemp("", "fake-gemini-*")
54		if err != nil {
55			t.Fatal(err)
56		}
57		defer os.Remove(f.Name())
58		if _, err := f.WriteString(script); err != nil {
59			t.Fatal(err)
60		}
61		f.Close()
62		if err := os.Chmod(f.Name(), 0o755); err != nil {
63			t.Fatal(err)
64		}
65	
66		r := &Runner{
67			Binary:   f.Name(),
68			BaseArgs: []string{},
69		}
70	
71		ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
72		defer cancel()
73	
74		ch, err := r.Execute(ctx, harnesses.ExecuteRequest{
75			Prompt: "test prompt",
76		})
77		if err != nil {
78			t.Fatalf("Execute: %v", err)
79		}
80	
81		var textDeltas []string
82		var finalEv *harnesses.FinalData
83		for ev := range ch {
84			switch ev.Type {
85			case harnesses.EventTypeTextDelta:
86				var d harnesses.TextDeltaData
87				if err := json.Unmarshal(ev.Data, &d); err != nil {
88					t.Errorf("unmarshal text_delta: %v", err)
89				}
90				textDeltas = append(textDeltas, d.Text)
91			case harnesses.EventTypeFinal:
92				var fd harnesses.FinalData
93				if err := json.Unmarshal(ev.Data, &fd); err != nil {
94					t.Errorf("unmarshal final: %v", err)
95				}
96				finalEv = &fd
97			}
98		}
99	
100		if len(textDeltas) == 0 {
101			t.Error("expected at least one text_delta event")
102		} else if !strings.Contains(textDeltas[0], "Hello from gemini") {
103			t.Errorf("unexpected text delta: %q", textDeltas[0])
104		}
105	
106		if finalEv == nil {
107			t.Fatal("no final event received")
108		}
109		if finalEv.Status != "success" {
110			t.Errorf("expected status=success, got %q (error: %s)", finalEv.Status, finalEv.Error)
111		}
112		if finalEv.FinalText != "Hello from gemini" {
113			t.Errorf("expected FinalText to contain gemini output, got %q", finalEv.FinalText)
114		}
115		// Usage from JSON result stats.
116		if finalEv.Usage == nil {
117			t.Error("expected usage in final event from JSON stats block")
118		} else {
119			if finalEv.Usage.InputTokens == nil || *finalEv.Usage.InputTokens != 12 {
120				t.Errorf("expected InputTokens=12, got %#v", finalEv.Usage.InputTokens)
121			}
122			if finalEv.Usage.OutputTokens == nil || *finalEv.Usage.OutputTokens != 13 { // total(25) - input(12)
123				t.Errorf("expected OutputTokens=13, got %#v", finalEv.Usage.OutputTokens)
124			}
125			if finalEv.Usage.TotalTokens == nil || *finalEv.Usage.TotalTokens != 25 {
126				t.Errorf("expected TotalTokens=25, got %#v", finalEv.Usage.TotalTokens)
127			}
128			if finalEv.Usage.CacheTokens == nil || *finalEv.Usage.CacheTokens != 2 {
129				t.Errorf("expected CacheTokens=2, got %#v", finalEv.Usage.CacheTokens)
130			}
131		}
132	}
