14	func killProcessGroup(cmd *osexec.Cmd) {
15		if cmd == nil || cmd.Process == nil {
16			return
17		}
18		pgid, err := syscall.Getpgid(cmd.Process.Pid)
19		if err != nil {
20			_ = cmd.Process.Signal(syscall.SIGTERM)
21			return
22		}
