9	// streamAggregate captures usage extracted from gemini output. HasUsage is
10	// set when the gemini stats / quota envelope was present at all (regardless
11	// of values), so explicit upstream zeros are preserved per CONTRACT-003.
12	type streamAggregate struct {
13		FinalText    string
14		HasUsage     bool
15		InputTokens  int
16		OutputTokens int
17		CacheTokens  int
18		TotalTokens  int
19		CostUSD      float64
20	}
