22	// geminiStatsEnvelope is a minimal view of the gemini JSON stats block.
23	// From DDx ExtractUsage("gemini"):
24	//
25	//	{"stats":{"models":{"<model>":{"tokens":{"input":N,"total":M}}}}}
26	//
27	// output_tokens = total - input.
28	type geminiStatsModel struct {
29		InputTokens  int `json:"input_tokens"`
30		OutputTokens int `json:"output_tokens"`
31		CacheTokens  int `json:"cached"`
32		TotalTokens  int `json:"total_tokens"`
33		Tokens       struct {
34			Input int `json:"input"`
35			Total int `json:"total"`
36		} `json:"tokens"`
37	}
