82	// parseGeminiUsage extracts token usage from the last non-empty line of
83	// gemini output that is a valid JSON stats envelope.
84	// Returns a streamAggregate with FinalText = full output.
85	func parseGeminiUsage(output string) *streamAggregate {
86		agg := &streamAggregate{FinalText: output}
87	
88		// Try last non-empty line (gemini may emit stats on the last line).
89		lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
90		last := ""
91		for i := len(lines) - 1; i >= 0; i-- {
92			if strings.TrimSpace(lines[i]) != "" {
93				last = lines[i]
94				break
95			}
96		}
97		if last == "" {
98			return agg
99		}
100	
101		var env geminiStatsEnvelope
102		if err := json.Unmarshal([]byte(last), &env); err != nil {
103			return agg
104		}
105	
106		applyGeminiStats(agg, env)
107		return agg
108	}
109	
110	func parseGeminiStreamOutput(output string) (*streamAggregate, bool) {
111		agg := &streamAggregate{}
112		var sawStreamEvent bool
113		lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
114		for _, rawLine := range lines {
115			line := strings.TrimSpace(rawLine)
116			if line == "" {
117				continue
118			}
119			var env geminiStreamEnvelope
120			if err := json.Unmarshal([]byte(line), &env); err != nil {
121				continue
122			}
123			switch env.Type {
124			case "init", "message", "result", "error":
125				sawStreamEvent = true
126			default:
127				continue
128			}
129			if env.Type == "message" && env.Role == "assistant" && env.Content != "" {
130				agg.FinalText += env.Content
131			}
132			if env.Type == "result" {
133				var stats geminiStatsEnvelope
134				if err := json.Unmarshal([]byte(line), &stats); err == nil {
135					applyGeminiStats(agg, stats)
136				}
137				if env.Status != "" && env.Status != "success" && env.Error != nil {
138					agg.FinalText = strings.TrimSpace(agg.FinalText)
139				}
140			}
141		}
142		return agg, sawStreamEvent
143	}
144	
145	func applyGeminiStats(agg *streamAggregate, env geminiStatsEnvelope) {
146		if env.Stats != nil {
147			agg.HasUsage = true
148			if env.Stats.InputTokens > 0 || env.Stats.OutputTokens > 0 || env.Stats.TotalTokens > 0 || env.Stats.CacheTokens > 0 {
149				agg.InputTokens = env.Stats.InputTokens
150				agg.OutputTokens = env.Stats.OutputTokens
151				agg.CacheTokens = env.Stats.CacheTokens
152				agg.TotalTokens = env.Stats.TotalTokens
153				if agg.TotalTokens == 0 && (agg.InputTokens > 0 || agg.OutputTokens > 0) {
154					agg.TotalTokens = agg.InputTokens + agg.OutputTokens
155				}
156			} else {
157				for _, model := range env.Stats.Models {
158					input := firstPositive(model.InputTokens, model.Tokens.Input)
159					output := model.OutputTokens
160					total := firstPositive(model.TotalTokens, model.Tokens.Total)
161					if output == 0 && total > 0 {
162						output = total - input
163					}
164					agg.InputTokens += input
165					agg.OutputTokens += output
166					agg.CacheTokens += model.CacheTokens
167					agg.TotalTokens += total
168				}
169				if agg.TotalTokens == 0 && (agg.InputTokens > 0 || agg.OutputTokens > 0) {
170					agg.TotalTokens = agg.InputTokens + agg.OutputTokens
171				}
172			}
173			agg.CostUSD = firstPositiveFloat(env.Stats.CostUSD, env.Stats.TotalCostUSD)
174		}
175		if env.Meta != nil {
176			agg.HasUsage = true
177			if env.Meta.Quota.TokenCount.InputTokens > 0 || env.Meta.Quota.TokenCount.OutputTokens > 0 || env.Meta.Quota.TokenCount.TotalTokens > 0 {
178				agg.InputTokens = env.Meta.Quota.TokenCount.InputTokens
179				agg.OutputTokens = env.Meta.Quota.TokenCount.OutputTokens
180				agg.TotalTokens = env.Meta.Quota.TokenCount.TotalTokens
181				if agg.TotalTokens == 0 {
182					agg.TotalTokens = agg.InputTokens + agg.OutputTokens
183				}
184			} else if len(env.Meta.Quota.ModelUsage) > 0 {
185				agg.InputTokens = 0
186				agg.OutputTokens = 0
187				agg.TotalTokens = 0
188				for _, model := range env.Meta.Quota.ModelUsage {
189					agg.InputTokens += model.TokenCount.InputTokens
190					agg.OutputTokens += model.TokenCount.OutputTokens
191					agg.TotalTokens += model.TokenCount.TotalTokens
192				}
193				if agg.TotalTokens == 0 {
194					agg.TotalTokens = agg.InputTokens + agg.OutputTokens
195				}
196			}
197		}
198	}
199	
200	func firstPositive(values ...int) int {
201		for _, value := range values {
202			if value > 0 {
203				return value
204			}
205		}
206		return 0
207	}
208	
209	func firstPositiveFloat(values ...float64) float64 {
210		for _, value := range values {
211			if value > 0 {
212				return value
213			}
214		}
215		return 0
216	}
217	
218	func geminiStreamError(output string) string {
219		lines := strings.Split(strings.TrimRight(output, "\n"), "\n")
220		for _, rawLine := range lines {
221			line := strings.TrimSpace(rawLine)
222			if line == "" {
223				continue
224			}
225			var env geminiStreamEnvelope
226			if err := json.Unmarshal([]byte(line), &env); err != nil || env.Type != "error" {
227				continue
228			}
229			if len(env.Error) == 0 {
230				return "gemini stream error"
231			}
232			var msg string
233			if err := json.Unmarshal(env.Error, &msg); err == nil && msg != "" {
234				return msg
235			}
236			var obj map[string]any
237			if err := json.Unmarshal(env.Error, &obj); err != nil {
238				return string(env.Error)
239			}
240			for _, key := range []string{"message", "error"} {
241				if value, ok := obj[key]; ok {
242					return strings.TrimSpace(toString(value))
243				}
244			}
245			return string(env.Error)
246		}
247		return ""
248	}
249	
250	func toString(value any) string {
251		switch v := value.(type) {
252		case string:
253			return v
254		case json.Number:
255			return v.String()
256		case float64:
257			return strconv.FormatFloat(v, 'f', -1, 64)
258		default:
259			data, err := json.Marshal(v)
260			if err != nil {
261				return ""
262			}
263			return string(data)
264		}
265	}
