9	// TestHarnessFinalEventPreservesUsageProvenance asserts that the gemini
10	// harness preserves the upstream provider's stats envelope verbatim,
11	// including explicit zero. Per CONTRACT-003, harnesses MUST NOT collapse
12	// zero with unknown.
13	func TestHarnessFinalEventPreservesUsageProvenance(t *testing.T) {
14		cases := []struct {
15			name       string
16			output     string
17			wantUsage  bool
18			wantInput  *int
19			wantOutput *int
20		}{
21			{
22				name:       "explicit_zero_stats_preserved",
23				output:     `{"stats":{"input_tokens":0,"output_tokens":0,"total_tokens":0}}`,
24				wantUsage:  true,
25				wantInput:  intPtr(0),
26				wantOutput: intPtr(0),
27			},
28			{
29				name:       "positive_stats_preserved",
30				output:     `{"stats":{"input_tokens":12,"output_tokens":3,"total_tokens":15}}`,
31				wantUsage:  true,
32				wantInput:  intPtr(12),
33				wantOutput: intPtr(3),
34			},
35			{
36				name:      "no_stats_envelope_stays_unknown",
37				output:    `not a json envelope at all`,
38				wantUsage: false,
39			},
40		}
41	
42		for _, tc := range cases {
43			t.Run(tc.name, func(t *testing.T) {
44				agg := parseGeminiUsage(tc.output)
45				if agg.HasUsage != tc.wantUsage {
46					t.Fatalf("HasUsage: got %v, want %v", agg.HasUsage, tc.wantUsage)
47				}
48	
49				var usage *harnesses.FinalUsage
50				if agg.HasUsage {
51					usage = &harnesses.FinalUsage{
52						InputTokens:  harnesses.IntPtr(agg.InputTokens),
53						OutputTokens: harnesses.IntPtr(agg.OutputTokens),
54					}
55				}
56	
57				if !tc.wantUsage {
58					if usage != nil {
59						t.Fatalf("harness silently emitted usage when provider sent none: %#v", usage)
60					}
61					return
62				}
63				if usage == nil {
64					t.Fatalf("harness dropped upstream stats envelope")
65				}
66				if usage.InputTokens == nil || *usage.InputTokens != *tc.wantInput {
67					t.Fatalf("InputTokens: got %#v, want *%d", usage.InputTokens, *tc.wantInput)
68				}
69				if usage.OutputTokens == nil || *usage.OutputTokens != *tc.wantOutput {
70					t.Fatalf("OutputTokens: got %#v, want *%d", usage.OutputTokens, *tc.wantOutput)
71				}
72			})
73		}
74	}
