63	// TestRecordRouteAttempt_DialFailureHardGatesProvider verifies FEAT-004 AC-28
64	// path: a route-attempt record whose Error matches a dispatchability-failure
65	// pattern (dial tcp / connection refused / i/o timeout / 5xx gateway) gets
66	// promoted into ProviderUnreachable so the next ResolveRoute hard-gates the
67	// provider — distinct from the soft-demotion path (context deadline,
68	// validation error) which leaves the candidate eligible but down-scored.
69	// This is the v0.13.1 follow-up to v0.13.0's snapshot-only hard-gate.
70	func TestRecordRouteAttempt_DialFailureHardGatesProvider(t *testing.T) {
71		cases := []struct {
72			name string
73			err  string
74		}{
75			{"dial tcp timeout", `openai: Post "http://bragi:1234/v1/chat/completions": dial tcp 100.127.38.115:1234: i/o timeout`},
76			{"connection refused", `dial tcp 192.168.2.106:8020: connection refused`},
77			{"502 bad gateway", `POST "http://bragi:1234/v1/chat/completions": 502 Bad Gateway `},
78			{"no route to host", `dial tcp: no route to host`},
79		}
80		for _, c := range cases {
81			t.Run(c.name, func(t *testing.T) {
82				svc := routeAttemptTestService(t, 30*time.Second)
83	
84				before, err := svc.ResolveRoute(context.Background(), RouteRequest{Model: "qwen"})
85				if err != nil {
86					t.Fatalf("ResolveRoute before failure: %v", err)
87				}
88				if before.Provider != "bragi" {
89					t.Fatalf("baseline provider: got %q, want bragi", before.Provider)
90				}
91	
92				if err := svc.RecordRouteAttempt(context.Background(), RouteAttempt{
93					Harness:  "fiz",
94					Provider: "bragi",
95					Model:    "qwen",
96					Status:   "failed",
97					Error:    c.err,
98				}); err != nil {
99					t.Fatalf("RecordRouteAttempt: %v", err)
100				}
101	
102				// After a dial-class failure, bragi must be hard-gated — its
103				// candidate row should be Eligible=false with FilterReasonUnhealthy.
104				after, err := svc.ResolveRoute(context.Background(), RouteRequest{Model: "qwen"})
105				if err != nil {
106					t.Fatalf("ResolveRoute after failure: %v", err)
107				}
108				if after.Provider == "bragi" {
109					t.Fatalf("after dial failure provider: got bragi, want hard-gated to alternative")
110				}
111				var bragiCand *RouteCandidate
112				for i := range after.Candidates {
113					if after.Candidates[i].Provider == "bragi" {
114						bragiCand = &after.Candidates[i]
115						break
116					}
117				}
118				if bragiCand == nil {
119					t.Fatal("bragi candidate row missing from decision")
120				}
121				if bragiCand.Eligible {
122					t.Errorf("bragi should be Eligible=false after dial failure; got Eligible=true")
123				}
124				if !strings.Contains(bragiCand.Reason, "known unreachable") {
125					t.Errorf("bragi.Reason = %q, want it to contain 'known unreachable'", bragiCand.Reason)
126				}
127	
128				// Explicit provider pin still selects bragi (operator bypass).
129				pinned, err := svc.ResolveRoute(context.Background(), RouteRequest{Model: "qwen", Provider: "bragi"})
130				if err != nil {
131					t.Fatalf("ResolveRoute with provider pin: %v", err)
132				}
133				if pinned.Provider != "bragi" {
134					t.Fatalf("explicit pin after dial failure: got %q, want bragi", pinned.Provider)
135				}
136			})
137		}
138	}
