284		successRate, _ = svc.routeMetricSignals(time.Now(), 30*time.Second)
285		if got, want := successRate[keyX], 0.0; got != want {
286			t.Fatalf("after success on modelY: successRate[%s]=%v, want %v (cross-pollution)", keyX, got, want)
