148	// AccountStatus implements harnesses.AccountHarness. Gemini's account
149	// state is sourced from authSnapshot (read from ~/.gemini and env).
150	func (r *Runner) AccountStatus(ctx context.Context, now time.Time) (harnesses.AccountSnapshot, error) {
151		if err := ctx.Err(); err != nil {
