103	func geminiQuotaSnapshotAge(snapshot *geminiQuotaSnapshot, now time.Time) time.Duration {
104		if snapshot == nil || snapshot.CapturedAt.IsZero() {
105			return 0
106		}
107		age := now.UTC().Sub(snapshot.CapturedAt.UTC())
108		if age < 0 {
109			return 0
110		}
111		return age
112	}
113	
114	func isGeminiQuotaFresh(snapshot *geminiQuotaSnapshot, now time.Time, staleAfter time.Duration) bool {
115		if snapshot == nil || snapshot.CapturedAt.IsZero() {
116			return false
117		}
118		if staleAfter <= 0 {
119			staleAfter = defaultGeminiQuotaStaleAfter
120		}
121		return geminiQuotaSnapshotAge(snapshot, now) <= staleAfter
122	}
123	
124	type geminiQuotaRoutingDecision struct {
125		preferGemini    bool
126		snapshotPresent bool
127		fresh           bool
128		age             time.Duration
129		snapshot        *geminiQuotaSnapshot
130		availableTiers  []string
131		exhaustedTiers  []string
132		reason          string
133	}
134	
135	func decideGeminiQuotaRouting(snapshot *geminiQuotaSnapshot, now time.Time, staleAfter time.Duration) geminiQuotaRoutingDecision {
136		decision := geminiQuotaRoutingDecision{snapshot: snapshot}
137		if snapshot == nil {
138			decision.reason = "no cached gemini quota snapshot; assume limited"
139			return decision
140		}
141		decision.snapshotPresent = true
142		decision.age = geminiQuotaSnapshotAge(snapshot, now)
143		if !isGeminiQuotaFresh(snapshot, now, staleAfter) {
144			decision.reason = "cached gemini quota snapshot is stale; assume limited"
145			return decision
146		}
147		decision.fresh = true
148		if len(snapshot.Windows) == 0 {
149			decision.reason = "fresh gemini quota snapshot has no tier windows; assume limited"
150			return decision
151		}
152		for _, w := range snapshot.Windows {
153			if isExhaustedWindow(w) {
154				decision.exhaustedTiers = append(decision.exhaustedTiers, w.LimitID)
155				continue
156			}
157			decision.availableTiers = append(decision.availableTiers, w.LimitID)
158		}
159		if len(decision.availableTiers) == 0 {
160			decision.reason = "fresh gemini quota snapshot reports all tiers exhausted; assume limited"
161			return decision
162		}
163		decision.preferGemini = true
164		decision.reason = "fresh gemini quota snapshot has at least one tier with headroom"
165		return decision
166	}
167	
168	func (d geminiQuotaRoutingDecision) isGeminiTierAvailable(model string) bool {
169		if !d.preferGemini {
170			return false
171		}
172		limitID, ok := TierLimitIDForModel(model)
173		if !ok {
174			return false
175		}
176		for _, tier := range d.availableTiers {
177			if tier == limitID {
178				return true
179			}
180		}
181		return false
182	}
183	
184	func (s *geminiQuotaSnapshot) maxUsedPercent() float64 {
185		if s == nil {
186			return 0
187		}
188		max := 0.0
189		for _, w := range s.Windows {
190			if w.UsedPercent > max {
191				max = w.UsedPercent
192			}
193		}
194		return max
195	}
196	
197	func isExhaustedWindow(w harnesses.QuotaWindow) bool {
198		if strings.EqualFold(w.State, "exhausted") || strings.EqualFold(w.State, "blocked") {
199			return true
200		}
201		return w.UsedPercent >= 95
202	}
